local function checkPlayerAndGoods(userId, goodsId)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    local goods = BlockShopConfig:getGoodsConfig(goodsId)
    if not goods then
        return
    end
    return player, goods
end

local function checkPlayerFirstInit(player)
    if TableUtil.getTableSize(player.block_goods) ~= 0 then
        return
    end
    local tabs = BlockShopConfig:getBlockShop()
    for _, tab in pairs(tabs) do
        local equipCount = BlockShopConfig:getEquipCount(tab.TabId)
        for _, goods in pairs(tab.GoodsList) do
            if goods.Default then
                local group = player.block_goods[tostring(goods.TabId)] or {}
                player.block_goods[tostring(goods.TabId)] = group
                if equipCount > 0 then
                    group[tostring(goods.Id)] = { goods.Id, BlockShopGoodsStatus.Equiped, goods.Time }
                else
                    group[tostring(goods.Id)] = { goods.Id, BlockShopGoodsStatus.UnEquip, goods.Time }
                end
                equipCount = equipCount - 1
            end
        end
    end
end

function BlockShop:init()
    EventObservable:registerDataCallBack("BuyBlockGoods", function(userId, goodsId)
        local player, goods = checkPlayerAndGoods(userId, goodsId)
        if not player then
            return
        end
        BlockShop:onBuyGoods(player, goods)
    end)

    EventObservable:registerDataCallBack("UnloadBlockGoods", function(userId, goodsId)
        local player, goods = checkPlayerAndGoods(userId, goodsId)
        if not player then
            return
        end
        BlockShop:onUnloadGoods(player, goods)
    end)

    EventObservable:registerDataCallBack("EquipBlockGoods", function(userId, goodsId)
        local player, goods = checkPlayerAndGoods(userId, goodsId)
        if not player then
            return
        end
        BlockShop:onEquipGoods(player, goods)
    end)
end

BlockShop:init()

function BlockShop:onSyncPlayerAllGoods(player)
    checkPlayerFirstInit(player)
    local result = {}
    for _, group in pairs(player.block_goods) do
        local remove = {}
        for goodsId, goods in pairs(group) do
            if goods[BlockGoodsIndex.Time] ~= -1 and os.time() > goods[BlockGoodsIndex.Time] then
                table.insert(remove, goodsId)
            else
                table.insert(result, goods)
            end
        end
        for _, goodsId in pairs(remove) do
            group[goodsId] = nil
        end
    end
    if #result > 0 then
        BlockShop:onPlayerGoodsChange(player, result)
    end
    if GameType == "g1046" then
        player.hall_day_key = player.hall_day_key or 0
        if player.hall_day_key ~= DateUtil.getYearDay() then
            CommonPacketSender:sendBlockShopRedPoint(player.rakssid)
            player.hall_day_key = DateUtil.getYearDay()
        end
    else
        player.game_day_key = player.game_day_key or 0
        if player.game_day_key ~= DateUtil.getYearDay() then
            CommonPacketSender:sendBlockShopRedPoint(player.rakssid)
            player.game_day_key = DateUtil.getYearDay()
        end
    end

end

function BlockShop:onPlayerGoodsChange(player, goodsList)
    CommonPacketSender:sendBlockShopData(player.rakssid, goodsList)
end

local function onBuyGoodsSuccess(player, goods)
    local group = player.block_goods[tostring(goods.TabId)] or {}
    local _goods = { goods.Id, BlockShopGoodsStatus.UnEquip, goods.Time }
    group[tostring(goods.Id)] = _goods
    BlockShop:onPlayerGoodsChange(player, { _goods })
    CommonPacketSender:sendBuyBlockGoodsSuccess(player.rakssid, goods.Id)
end

function BlockShop:onBuyGoods(player, goods, free)
    if goods.Price < 0 then
        return
    end
    local group = player.block_goods[tostring(goods.TabId)] or {}
    player.block_goods[tostring(goods.TabId)] = group
    for _, _goods in pairs(group) do
        if _goods[BlockGoodsIndex.Id] == goods.Id then
            return ---已购买，无需再次购买
        end
    end
    if free then
        onBuyGoodsSuccess(player, goods)
        return true
    end
    if not MoneyUtil:checkHasMoney(player, Define.Money.DIAMOND, goods.Price) then
        return
    end
    PayHelper.payDiamondsSync(player.userId, goods.Id, goods.Price, function()
        onBuyGoodsSuccess(player, goods)
        return true
    end)
end

function BlockShop:onEquipGoods(player, goods)
    local group = player.block_goods[tostring(goods.TabId)]
    if not group then
        return
    end
    local result = {}
    for _, _goods in pairs(group) do
        if _goods[BlockGoodsIndex.Status] == BlockShopGoodsStatus.Equiped then
            _goods[BlockGoodsIndex.Status] = BlockShopGoodsStatus.UnEquip
            local goodsConfig = BlockShopConfig:getGoodsConfig(_goods[BlockGoodsIndex.Id])
            if goodsConfig and goodsConfig.Type == goods.Type then
                table.insert(result, _goods)
            end
        end
    end
    local _goods = group[tostring(goods.Id)]
    if not _goods then
        return
    end
    if _goods[BlockGoodsIndex.Status] == BlockShopGoodsStatus.Equiped then
        return
    end
    _goods[BlockGoodsIndex.Status] = BlockShopGoodsStatus.Equiped
    table.insert(result, _goods)
    BlockShop:onPlayerGoodsChange(player, result)
    if goods.Type == BlockShopConfig.Type.Skin then
        player.skin_order[tostring(goods.TabId)] = goods.Order
    else
        player.wall_order[tostring(goods.TabId)] = goods.Order
    end
    self:onBlockMapChange(player, goods.TabId)
end

function BlockShop:onUnloadGoods(player, goods)
    local group = player.block_goods[tostring(goods.TabId)]
    if not group then
        return
    end
    local _goods = group[tostring(goods.Id)]
    if not _goods then
        return
    end
    if _goods[BlockGoodsIndex.Status] == BlockShopGoodsStatus.UnEquip then
        return
    end
    _goods[BlockGoodsIndex.Status] = BlockShopGoodsStatus.UnEquip
    BlockShop:onPlayerGoodsChange(player, { _goods })
    if goods.Type == BlockShopConfig.Type.Skin then
        player.skin_order[tostring(goods.TabId)] = nil
    else
        player.wall_order[tostring(goods.TabId)] = nil
    end
    self:onBlockMapChange(player, goods.TabId)
end

function BlockShop:onBlockMapChange(player, tabId)
    local skinOrder = player.skin_order[tostring(tabId)] or 0
    local WallOrder = player.wall_order[tostring(tabId)] or 0
    local map = BlockShopConfig:getBlockMap(tabId, skinOrder, WallOrder)
    if not map then
        return
    end
    ---获取原来的装备的方块装扮
    local oldBlockId = map.BlockId
    ---原来的装扮是羊毛原型(BlockId=35)，需要替换成队伍的羊毛方块Id
    if GameType ~= "g1046" then
        if oldBlockId == BlockID.CLOTH then
            oldBlockId = player:getClothBlockId()
        end
        oldBlockId = player:tryItemId2DressId(oldBlockId)
    end
    local blockItemId = BlockManager.getItemBlockId(oldBlockId)
    ---设置新的方块装扮
    player.equip_dress[tostring(map.BlockId)] = map.DressBlockId
    local inv = player:getInventory()
    for index = 0, 35 do
        local info = inv:getItemStackInfo(index)
        if info.id == blockItemId then
            inv:decrStackSize(index, info.num)
            player:tryAddItem(map.BlockId, info.num)
        end
    end
end
